assign rott_edge = rott && !rott_prev;

// 方块形状查找表
function logic [15:0] get_shape(input [2:0] piece_type, input [1:0] piece_rot);
    case(piece_type)
        3'b000: get_shape = (piece_rot[0]) ? 16'b0100010001000100 : 16'b0000111100000000;
        3'b001: get_shape = 16'b0000011001100000;
        3'b010: case(piece_rot)
                    2'b00: get_shape = 16'b0000010011100000;
                    2'b01: get_shape = 16'b0000010001100100;
                    2'b10: get_shape = 16'b0000000011100100;
                    2'b11: get_shape = 16'b0000010011000100;
                endcase
        3'b011: case(piece_rot)
                    2'b00: get_shape = 16'b0100010001100000;
                    2'b01: get_shape = 16'b0111010000000000;
                    2'b10: get_shape = 16'b0011000100010000;
                    2'b11: get_shape = 16'b0000000101110000;
                endcase
        3'b100: case(piece_rot)
                    2'b00: get_shape = 16'b0000001000100110;
                    2'b01: get_shape = 16'b0000100011100000;
                    2'b10: get_shape = 16'b0000011001000100;
                    2'b11: get_shape = 16'b0000000011100010;
                endcase
        3'b101: get_shape = (piece_rot[0]) ? 16'b0000010001100010 : 16'b0000001101100000;
        3'b110: get_shape = (piece_rot[0]) ? 16'b0000001001100100 : 16'b0000011000110000;
        default: get_shape = 16'b0;
    endcase
endfunction

// Collision check function
// Returns 1 if collision detected, 0 otherwise
function logic check_collision(input [2:0] piece_type, input [1:0]piece_rot, input logic signed[4:0] piece_x, input [4:0] piece_y);
    shape_map = get_shape(piece_type, piece_rot);
    for (int i = 0; i < 4; i++) begin
        for (int j = 0; j < 4; j++) begin
            if(shape_map[15 - (i*4 + j)]) begin
                automatic int grid_x = piece_x + j;
                automatic int grid_y = piece_y + i;
                if (grid_x < 0 || grid_x > 9 || grid_y > 19) return 1;
                if (grid_y >= 0 && gm_memory[grid_y][grid_x] != 4'b0) return 1;
            end
        end
    end
    return 0;
endfunction

// 计算最大下落距离，实时计算（组合逻辑）
logic [4:0] drop_distance;

// 辅助函数：计算单列的距离
function logic [4:0] get_column_distance(input logic signed [4:0] col_idx, input [4:0] start_y);
    logic [19:0] col_occupied;
    logic [19:0] masked_occupied;
    logic [4:0] hit_y;

    // 1. 提取列占用情况 (手动展开，避免 for)
    if (col_idx >= 0 && col_idx <= 9) begin
        col_occupied[0] = |gm_memory[0][col_idx];
        col_occupied[1] = |gm_memory[1][col_idx];
        col_occupied[2] = |gm_memory[2][col_idx];
        col_occupied[3] = |gm_memory[3][col_idx];
        col_occupied[4] = |gm_memory[4][col_idx];
        col_occupied[5] = |gm_memory[5][col_idx];
        col_occupied[6] = |gm_memory[6][col_idx];
        col_occupied[7] = |gm_memory[7][col_idx];
        col_occupied[8] = |gm_memory[8][col_idx];
        col_occupied[9] = |gm_memory[9][col_idx];
        col_occupied[10] = |gm_memory[10][col_idx];
        col_occupied[11] = |gm_memory[11][col_idx];
        col_occupied[12] = |gm_memory[12][col_idx];
        col_occupied[13] = |gm_memory[13][col_idx];
        col_occupied[14] = |gm_memory[14][col_idx];
        col_occupied[15] = |gm_memory[15][col_idx];
        col_occupied[16] = |gm_memory[16][col_idx];
        col_occupied[17] = |gm_memory[17][col_idx];
        col_occupied[18] = |gm_memory[18][col_idx];
        col_occupied[19] = |gm_memory[19][col_idx];
    end else begin
        return 0; // 出界
    end

    // 2. 屏蔽掉 start_y 及之上的部分
    // mask: 高位为 1，低位为 0。我们要保留 > start_y 的位。
    masked_occupied = col_occupied & (20'hFFFFF << (start_y + 1));

    // 3. 找到第一个 1 (Priority Encoder)
    if (masked_occupied[0]) hit_y = 0;
    else if (masked_occupied[1]) hit_y = 1;
    else if (masked_occupied[2]) hit_y = 2;
    else if (masked_occupied[3]) hit_y = 3;
    else if (masked_occupied[4]) hit_y = 4;
    else if (masked_occupied[5]) hit_y = 5;
    else if (masked_occupied[6]) hit_y = 6;
    else if (masked_occupied[7]) hit_y = 7;
    else if (masked_occupied[8]) hit_y = 8;
    else if (masked_occupied[9]) hit_y = 9;
    else if (masked_occupied[10]) hit_y = 10;
    else if (masked_occupied[11]) hit_y = 11;
    else if (masked_occupied[12]) hit_y = 12;
    else if (masked_occupied[13]) hit_y = 13;
    else if (masked_occupied[14]) hit_y = 14;
    else if (masked_occupied[15]) hit_y = 15;
    else if (masked_occupied[16]) hit_y = 16;
    else if (masked_occupied[17]) hit_y = 17;
    else if (masked_occupied[18]) hit_y = 18;
    else if (masked_occupied[19]) hit_y = 19;
    else hit_y = 20; // 底部

    return hit_y - start_y - 1;
endfunction

always_comb begin
    logic [15:0] shape;
    logic [4:0] d0, d1, d2, d3;
    logic [4:0] min1, min2;

    shape = get_shape(active_block, rotate);

    // Col 0 (x)
    if (shape[3]) d0 = get_column_distance(active_x, active_y + 3);
    else if (shape[7]) d0 = get_column_distance(active_x, active_y + 2);
    else if (shape[11]) d0 = get_column_distance(active_x, active_y + 1);
    else if (shape[15]) d0 = get_column_distance(active_x, active_y + 0);
    else d0 = 20; // 该列无方块

    // Col 1 (x+1)
    if (shape[2]) d1 = get_column_distance(active_x + 1, active_y + 3);
    else if (shape[6]) d1 = get_column_distance(active_x + 1, active_y + 2);
    else if (shape[10]) d1 = get_column_distance(active_x + 1, active_y + 1);
    else if (shape[14]) d1 = get_column_distance(active_x + 1, active_y + 0);
    else d1 = 20;

    // Col 2 (x+2)
    if (shape[1]) d2 = get_column_distance(active_x + 2, active_y + 3);
    else if (shape[5]) d2 = get_column_distance(active_x + 2, active_y + 2);
    else if (shape[9]) d2 = get_column_distance(active_x + 2, active_y + 1);
    else if (shape[13]) d2 = get_column_distance(active_x + 2, active_y + 0);
    else d2 = 20;

    // Col 3 (x+3)
    if (shape[0]) d3 = get_column_distance(active_x + 3, active_y + 3);
    else if (shape[4]) d3 = get_column_distance(active_x + 3, active_y + 2);
    else if (shape[8]) d3 = get_column_distance(active_x + 3, active_y + 1);
    else if (shape[12]) d3 = get_column_distance(active_x + 3, active_y + 0);
    else d3 = 20;

    min1 = (d0 < d1) ? d0 : d1;
    min2 = (d2 < d3) ? d2 : d3;
    drop_distance = (min1 < min2) ? min1 : min2;
end

// LFSR for random block generation
lfsr_galois_3bit u_lfsr_galois_3bit (
    .clk(gm_clk),
    .rst(gm_rst),
    .random_out(random_block)
);

// Game logic FSM
always_ff @(posedge gm_clk) begin
    if (gm_rst) begin
        gm_state <= 3'b000;
    end else begin

        case(gm_state)
            3'b000: begin // INIT - sequential clear instead of nested for
                for(int i = 0; i < 20; i++)
                    for(int j = 0; j < 10; j++)
                        gm_memory[i][j] <= 4'b0;
                gm_score <= 16'b0;
                active_block <= 3'b000;
                gm_state <= 3'b001;
            end
            3'b001: begin // SPAWN
                active_block <= random_block - 3'b001; // Map LFSR output to block types 0-6
                rotate <= 2'b00;
                active_x <= 5'd4;
                active_y <= 5'd0;
                if (check_collision(active_block, 2'b00, 5'd4, 5'd0)) // Use current active_block
                    gm_state <= 3'b101;
                else
                    gm_state <= 3'b010;
            end
            3'b010: begin // FALLING
                automatic logic signed [4:0] next_x = active_x;
                automatic logic [4:0] next_y = active_y;
                automatic logic [1:0] next_rot = rotate;
                automatic logic moved_by_player = 1'b0;

                // --- Step 1: Handle Player Input First ---
                if (left_edge) begin
                    next_x = active_x - 1;
                    moved_by_player = 1'b1;
                end else if (right_edge) begin
                    next_x = active_x + 1;
                    moved_by_player = 1'b1;
                end else if (rott_edge) begin
                    next_rot = rotate + 1;
                    moved_by_player = 1'b1;
                end

                // --- Step 2: Test the Player's Move ---
                if (moved_by_player && !check_collision(active_block, next_rot, next_x, active_y)) begin
                    active_x <= next_x;
                    rotate <= next_rot;
                end

                // --- Step 3: Handle Downward Movement ---
                if (grav_ce || down_edge) begin // Use continuous 'down' for soft drop
                    if (down_edge) begin
                        next_y = active_y + drop_distance; // 硬降落
                        active_y <= next_y;
                        gm_state <= 3'b011; // Piece has landed
                    end else begin
                        next_y = active_y + 1;
                        if (!check_collision(active_block, rotate, active_x, next_y)) begin
                            active_y <= next_y; // Keep falling
                        end else begin
                            gm_state <= 3'b011; // Piece has landed
                        end
                    end
                end
            end
            3'b011: begin // LANDED
                automatic logic [15:0] landed_shape = get_shape(active_block, rotate);
                for (int i = 0; i < 4; i++) begin
                    for (int j = 0; j < 4; j++) begin
                        automatic int gx = $signed(active_x) + j;
                        automatic int gy = active_y + i;
                        if (landed_shape[15-(i*4+j)] && gy >= 0 && gy < 20 && gx >= 0 && gx < 10) begin
                            gm_memory[gy][gx] <= active_block + 1;
                        end
                    end
                end
                gm_state <= 3'b100;
            end
            3'b100: begin // CLEAR LINES - sequential copy approach could be added here if needed
                automatic int write_row = 19;
                automatic int lines_cleared = 0;
                automatic logic [3:0] new_grid [19:0][9:0];


                // Pass 1: Create a temporary grid that is completely empty.
                for (int i = 0; i < 20; i++) begin
                    for (int j = 0; j < 10; j++) begin
                        new_grid[i][j] = 4'h0;
                    end
                end

                // Pass 2: Copy only the non-full rows from the old grid to the new one.
                for (int read_row = 19; read_row >= 0; read_row--) begin
                    automatic bit line_is_full = 1'b1;
                    for (int col = 0; col < 10; col++) begin
                        if (gm_memory[read_row][col] == 4'h0) begin
                            line_is_full = 1'b0;
                        end
                    end

                    if (!line_is_full) begin
                        // If the row is not full, copy it to the 'write_row' position.
                        for (int col = 0; col < 10; col++) begin
                            new_grid[write_row][col] = gm_memory[read_row][col];
                        end
                        write_row = write_row - 1; // Move the write position up.
                    end else begin
                        lines_cleared = lines_cleared + 1;
                    end
                end

                // Update the main grid and score if any lines were cleared.
                if (lines_cleared > 0) begin
                    gm_memory <= new_grid;
                    gm_score  <= gm_score + (lines_cleared * lines_cleared * 100);
                end

                // Always go back to SPAWN to continue the game.
                gm_state <= 3'b001;
            end
            3'b101: begin //GAME OVER
                if(gm_rst) begin
                    gm_state <= 3'b000; // Go to initialization on reset
                end
            end
            default: begin
                gm_state <= 3'b000; // Reset to initialization on unknown state
            end
        endcase
    end
end

// Display output composition
always_comb begin
    automatic logic [3:0] temp_grid [19:0][9:0] = gm_memory;
    case(active_block)
        3'b000: active_color = 4'b0001;
        3'b001: active_color = 4'b0010;
        3'b010: active_color = 4'b0011;
        3'b011: active_color = 4'b0100;
        3'b100: active_color = 4'b0101;
        3'b101: active_color = 4'b0110;
        3'b110: active_color = 4'b0111;
        default: active_color = 4'b0000;
    endcase
    shape_map1 = get_shape(active_block, rotate);
    if (gm_state == 3'b010 || gm_state == 3'b001) begin
        for (int i = 0; i < 4; i++)
            for (int j = 0; j < 4; j++)// 绘制活动方块,16位表示4x4方块
                if(shape_map1[15 - (i*4 + j)] && active_y + i < 20 && $signed(active_x) + j >= 0 && $signed(active_x) + j < 10)
                    temp_grid[active_y + i][$signed(active_x) + j] = active_color;
    end
    grid = temp_grid;
    score = gm_score;
end

endmodule
